impl Solution { pub fn minimum_operations_to_make_equal(x: i32, y: i32) -> i32 { if y >= x { return y - x; } let mut black_q = std::collections::VecDeque::from([(x, 0)]); let mut black_v = std::collections::HashSet::from([x]); while let Some((curr, d)) = black_q.pop_front() { if curr == y { return d; } for next in [if curr % 11 == 0 { Some(curr/11) } else { None }, if curr % 5 == 0 { Some(curr/5) } else { None }, Some(curr-1), Some(curr+1)] { if let Some(v) = next { if v > 0 && v < 10000 + x && black_v.insert(v) { black_q.push_back((v, d+1)); } } } } 0 } }